plist.dict:
CFBundlePackageType
APPL
CFBundleName
{{.Info.ProductName}}
CFBundleExecutable
{{.OutputFilename}}
CFBundleIdentifier
com.wails.{{.Name}}
CFBundleVersion
{{.Info.ProductVersion}}
CFBundleGetInfoString
{{.Info.Comments}}
CFBundleShortVersionString
{{.Info.ProductVersion}}
CFBundleIconFile
iconfile
LSMinimumSystemVersion
10.15.0
NSHighResolutionCapable
true
NSHumanReadableCopyright
{{.Info.Copyright}}
NSDesktopFolderUsageDescription
MaClaw needs access to your Desktop folder to manage project files.
NSDocumentsFolderUsageDescription
MaClaw needs access to your Documents folder to manage project files.
NSDownloadsFolderUsageDescription
MaClaw needs access to your Downloads folder to install tools and updates.
NSLocalNetworkUsageDescription
MaClaw uses local network to discover and connect to Hub services.
NSPhotoLibraryUsageDescription
MaClaw needs photo library access to process screenshots and images.
NSScreenCaptureUsageDescription
MaClaw needs screen recording permission to capture screenshots for remote coding sessions.
{{if .Info.FileAssociations}}
CFBundleDocumentTypes

  {{range .Info.FileAssociations}}

    CFBundleTypeExtensions

      {{.Ext}}

    CFBundleTypeName
    {{.Name}}
    CFBundleTypeRole
    {{.Role}}
    CFBundleTypeIconFile
    {{.IconName}}

  {{end}}

{{end}}
{{if .Info.Protocols}}
CFBundleURLTypes

  {{range .Info.Protocols}}

        CFBundleURLName
        com.wails.{{.Scheme}}
        CFBundleURLSchemes

            {{.Scheme}}

        CFBundleTypeRole
        {{.Role}}

  {{end}}

{{end}}
NSAppTransportSecurity

    NSAllowsLocalNetworking
